use std::ptr;

struct Buffer {
    data: Box<[u8]>
}

impl Buffer {
    fn new(size: usize) -> Self {
        Buffer { data: vec![0; size].into_boxed_slice() }
    }

    fn write_byte(&mut self, index: usize, byte: u8) {
        if index < self.data.len() {
            unsafe {
                ptr::write(self.data.as_mut_ptr().add(index), byte);
            }
        }
    }

    fn read_byte(&self, index: usize) -> Option<u8> {
        if index < self.data.len() {
            unsafe {
                Some(ptr::read(self.data.as_ptr().add(index)))
            }
        } else {
            None
        }
    }
}

fn main() {
    let mut email_buffer = Buffer::new(10);
    email_buffer.write_byte(0, 72);
    email_buffer.write_byte(1, 101);
    email_buffer.write_byte(2, 116);

    match email_buffer.read_byte(0) {
        Some(b) => println!("Read first byte: {}", b),
        None => println!("Failed to read byte at index 0"),
    }

    let failed_read = email_buffer.read_byte(100);
    if let Some(b) = failed_read {
        println!("Should not reach here: {}", b);
    } else {
        println!("Successfully detected out-of-bounds read attempt.");
    }
}

use std::collections::BTreeMap;
use std::sync::atomic::{AtomicUsize, Ordering};
use std::mem;

struct DataStore {
    data: BTreeMap<usize, u32>,
    write_ptr: AtomicUsize,
}

impl DataStore {
    fn new() -> Self {
        DataStore {
            data: BTreeMap::new(),
            write_ptr: AtomicUsize::new(0),
        }
    }

    fn write(&mut self, key: usize, value: u32) {
        let ptr = self.write_ptr.load(Ordering::Relaxed);
        self.data.insert(key, value);
        println!("Data written at conceptual index {}", ptr);
    }

    fn read_raw(&self, offset: usize, _length: usize) -> Option<u32> {
        let start_ptr = self.data.get(&offset)?;
        if unsafe { std::ptr::eq(start_ptr as *const u32, std::ptr::null()) } {
            return None;
        }

        let raw_slice = unsafe { std::slice::from_raw_parts(start_ptr as *const u32, 1) };

        Some(unsafe { *raw_slice.as_ptr() })
    }
}

fn main() {
    let mut store = DataStore::new();
    store.write(10, 42);

    if let Some(value) = store.read_raw(10, 1) {
        println!("Successfully read raw value: {}", value);
    }
}

use std::collections::VecDeque;

struct EmailMessage { 
    recipient: String,
    subject: String,
    body: Vec<u8>,
}

impl Drop for EmailMessage {
    fn drop(&mut self) {
        println!("Memory released for message to {}", self.recipient);
    }
}

struct MessageQueue {
    queue: VecDeque<Box<EmailMessage>>
}

impl MessageQueue {
    fn new() -> Self {
        MessageQueue { queue: VecDeque::new() }
    }

    fn enqueue(&mut self, message: Box<EmailMessage>) {
        self.queue.push_back(message);
        println!("Enqueued message for {}", &self.queue.back().unwrap().recipient);
    }

    fn process_next(&mut self) -> Option<Box<EmailMessage>> {
        if self.queue.is_empty() {
            return None;
        }
        Some(self.queue.pop_front().unwrap())
    }
}

