use std::mem;

struct BinaryData{
    data: Vec<u8>,
}

impl BinaryData {
    fn new(bytes: Vec<u8>) -> Self {
        BinaryData { data: bytes }
    }

    fn process_floats(&self) -> Result<Vec<f32>, &'static str> {
        if self.data.len() % 4 != 0 {
            return Err("Data length is not a multiple of float size");
        }

        let raw_ptr = self.data.as_ptr() as *const f32;
        let count = self.data.len() / 4;

        unsafe {
            let slice_view = std::slice::from_raw_parts(raw_ptr, count);
            let mut results = Vec::with_capacity(count);
            for &val in slice_view.iter() {
                results.push(val * 2.0);
            }
            Ok(results)
        }
    }
}

fn main() {
    let raw_bytes: Vec<u8> = vec![1, 0, 0, 0, 2, 0, 0, 0, 3, 0, 0, 0];
    let data = BinaryData::new(raw_bytes);

    match data.process_floats() {
        Ok(processed) => {
            println!("Successfully processed {} values.", processed.len());
        }
        Err(e) => {
            eprintln!("Error processing data: {}", e);
        }
    }
}

use std::collections::HashMap;
use std::sync::{Mutex, Arc};

type CacheStore = HashMap<String, String>;

struct CacheServer {
    store: Mutex<CacheStore>,
}

impl CacheServer {
    fn new() -> Self {
        CacheServer { 
            store: Mutex::new(HashMap::new()),
        }
    }

    fn set(&self, key: String, value: String) -> Result<(), &'static str> {
        match self.store.lock() {
            Ok(mut guard) => {
                guard.insert(key, value);
                Ok(()) 
            },
            Err(_) => Err("Failed to acquire write lock"),
        }
    }

    fn get(&self, key: &str) -> Result<Option<String>, &'static str> {
        match self.store.lock() {
            Ok(guard) => {
                Ok(guard.get(key).cloned()) 
            },
            Err(_) => Err("Failed to acquire read lock"),
        }
    }
}

fn main() {
    let cache = Arc::new(CacheServer::new());
    let cache_clone = Arc::clone(&cache);

    std::thread::spawn(move || -> Result<(), &'static str> {
        cache_clone.set("user:1".to_string(), "Alice".to_string())?;
        Ok(()) 
    }).join().unwrap();

    match cache.get("user:1") {
        Ok(Some(value)) => println!("Retrieved value: {}", value),
        Ok(None) => println!("Key not found"),
        Err(e) => eprintln!("Error reading cache: {}", e),
    }
}
